const https = require('https');

const token = process.env.TELEGRAM_BOT_TOKEN || '';
const lastId = $workflow.staticData.lastUpdateId || 0;

const response = await new Promise((resolve, reject) => {
  https.get(`https://api.telegram.org/bot${token}/getUpdates?offset=${lastId}&timeout=8`, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try { resolve(JSON.parse(data)); }
      catch(e) { reject(e); }
    });
  }).on('error', reject);
});

if (!response.ok || !response.result || response.result.length === 0) {
  return [{ json: { _empty: true } }];
}

let maxId = lastId;
const results = [];

for (const update of response.result) {
  const msg = update.message || {};
  const chatId = msg.chat?.id;
  const text = (msg.text || '').trim();
  if (!chatId || !text || text.startsWith('/')) continue;
  maxId = Math.max(maxId, update.update_id);
  results.push({ json: { chatId: chatId, text: text } });
}

$workflow.staticData.lastUpdateId = maxId;
return results.length > 0 ? results : [{ json: { _empty: true } }];

const item = $input.first().json;
const userText = item.text;
const chatId = item.chatId;

const https = require('https');
const apiKey = process.env.DEEPSEEK_API_KEY || '';

const sysPrompt = '你係信用卡達人 + 搵工達人 + 補習老師。三大功能：\n【信用卡】精通香港各銀行信用卡年費、回贈、里數、優惠、迎新。\n【搵工】提供香港招聘資訊、求職建議、CV tips、面試技巧。\n【補習】教小學生做功課，用簡單方法解釋概念，鼓勵思考。\n回答簡潔準確，用廣東話/繁體中文，200字以內。';

const payload = JSON.stringify({
  model: 'deepseek-v4-flash',
  messages: [
    { role: 'system', content: sysPrompt },
    { role: 'user', content: userText }
  ],
  max_tokens: 600,
  temperature: 0.7
});

const response = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.deepseek.com', path: '/v1/chat/completions', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey }
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try { resolve(JSON.parse(data)); }
      catch(e) { reject(new Error('parse: ' + data.slice(0,200))); }
    });
  });
  req.on('error', reject);
  req.write(payload);
  req.end();
});

const reply = response?.choices?.[0]?.message?.content || '唔好意思，處理唔到。';
return [{ json: { chatId: chatId, reply: reply } }];
